type paramMap struct {
	Key   string
	Value string
}

type Request struct {
	Context             context.Context
	Method              string
	Path                string
	Headers             map[string]string
	QueryParams         map[string]string
	PathParams          map[string]string
	Options             any
	Body                any
	Config              magicbellprojectclientconfig.Config
	ContentType         ContentType
	ResponseContentType ContentType
}

func NewRequest(ctx context.Context, method string, path string, config magicbellprojectclientconfig.Config) Request {
	return Request{
		Context:             ctx,
		Method:              method,
		Path:                path,
		Headers:             make(map[string]string),
		QueryParams:         make(map[string]string),
		PathParams:          make(map[string]string),
		Config:              config,
		ContentType:         ContentTypeJson,
		ResponseContentType: ContentTypeJson,
	}
}

func (r *Request) Clone() Request {
	if r == nil {
		return Request{
			Headers:     make(map[string]string),
			QueryParams: make(map[string]string),
			PathParams:  make(map[string]string),
		}
	}

	clone := *r
	clone.PathParams = utils.CloneMap(r.PathParams)
	clone.Headers = utils.CloneMap(r.Headers)
	clone.QueryParams = utils.CloneMap(r.QueryParams)

	return clone
}

