package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
)

// Recipient represents a notification recipient.
type Recipient struct {
	Email string `json:"email"`
}

// BroadcastRequest is the payload for the MagicBell broadcast API.
type BroadcastRequest struct {
	Title      string      `json:"title"`
	Content    string      `json:"content"`
	ActionURL  string      `json:"action_url"`
	Recipients []Recipient `json:"recipients"`
}

// BroadcastResponse holds relevant fields from the API response.
type BroadcastResponse struct {
	ID string `json:"id"`
}

func main() {
	// Read environment variables
	runID := os.Getenv("ZEALT_RUN_ID")
	if runID == "" {
		log.Fatal("ZEALT_RUN_ID environment variable is not set")
	}

	magicbellEmail := os.Getenv("MAGICBELL_EMAIL")
	if magicbellEmail == "" {
		log.Fatal("MAGICBELL_EMAIL environment variable is not set")
	}

	projectToken := os.Getenv("MAGICBELL_PROJECT_TOKEN")
	if projectToken == "" {
		log.Fatal("MAGICBELL_PROJECT_TOKEN environment variable is not set")
	}

	// Construct recipient email and action URL from the run ID
	recipientEmail := fmt.Sprintf("%s+%s@gmail.com", magicbellEmail, runID)
	actionURL := fmt.Sprintf("https://example.com/action-%s", runID)

	// Build the broadcast payload
	payload := BroadcastRequest{
		Title:     "Action Required: Important Notification",
		Content:   "Please click the link below to complete your action.",
		ActionURL: actionURL,
		Recipients: []Recipient{
			{Email: recipientEmail},
		},
	}

	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		log.Fatalf("Failed to marshal request payload: %v", err)
	}

	// Send the POST request to the MagicBell broadcasts API
	apiURL := "https://api.magicbell.com/broadcasts"
	req, err := http.NewRequest("POST", apiURL, bytes.NewReader(payloadBytes))
	if err != nil {
		log.Fatalf("Failed to create HTTP request: %v", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-MAGICBELL-API-KEY", projectToken)

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		log.Fatalf("Failed to send HTTP request: %v", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		log.Fatalf("Failed to read response body: %v", err)
	}

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		log.Fatalf("API request failed with status %d: %s", resp.StatusCode, string(body))
	}

	// Parse the response to extract the broadcast ID
	var broadcastResp BroadcastResponse
	if err := json.Unmarshal(body, &broadcastResp); err != nil {
		log.Fatalf("Failed to parse response JSON: %v\nBody: %s", err, string(body))
	}

	if broadcastResp.ID == "" {
