}

func (r *ErrorResponse[T]) SetHeader(header string, value string) {
	r.Headers[header] = value
}

func (r *ErrorResponse[T]) GetBody() []byte {
	return r.Body
}

func (r *ErrorResponse[T]) SetBody(body []byte) {
